    int rootDomainId=Encoder.parseInt(request.getParameter("rd"),Const.NODOMAIN);
    String path=request.getParameter("p");
    int sheetIndex=Encoder.parseInt(request.getParameter("si"));
    boolean showMultipleVersions = Encoder.parseBoolean(request.getParameter("all"), false);

    //privilege check
    User user=(User)session.getAttribute("USER");
    if(user==null || !user.ifApManager(apname)) return;
    
    //NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
