    //show all history versions of configurations, including multiple versions
    List<HistoryLine> historyList = new ArrayList<>();
    List<String> copiedUrlList = Account.getInstance(apname).getCopiedUrlList(rootDomainId);
    for (String url : copiedUrlList) {
        String[] split = url.split("/");
        //[BugId:11143]
        if (!showMultipleVersions && (!path.equals("/" + split[1]) || sheetIndex != Encoder.parseInt(split[2]))) {
            continue;
        }
        NUIForm copiedForm = AppManager.getFormPage(split[0], "/" + split[1], Encoder.parseInt(split[2]));
        if (copiedForm == null) continue;
        Set<NUIForm.NUIFormHistory> designHistoryList=copiedForm.retrieveDesignHistory(bundle);
        NUIForm.NUIFormHistory lastVersion=null;
        NUIForm lastVersionForm=null;
        for(NUIForm.NUIFormHistory history:designHistoryList){
            NUIForm.NUIFormHistory currentVersion=history;
            NUIForm currentForm=copiedForm.getHistoryForm(currentVersion.getVersion());
            //[BugId:10761]
            if(lastVersion!=null){
                lastVersionForm.setBundle(bundle);
                List<NUIFormDiffItem> diffList=lastVersionForm.compareVersions(currentForm,domainId);
                //System.out.println("Diff:"+lastVersion.getVersion()+"-"+currentVersion.getVersion());
                for(NUIFormDiffItem item:diffList){
                    if(item.getDomainId()==domainId){
                        historyList.add(new HistoryLine(history.getDate(),
                                "<tr>" +
                                "<td><a href='/"+copiedForm.getUrl()+"' target='_blank'>"+copiedForm.getRealname()+"</td>" +
                                "<td>"+Encoder.formatAsStandardDate(lastVersion.getDate(),true)+" ("+lastVersion.getVersion()+")</td>" +
                                "<td>"+(lastVersion.getEmail()==null?"":lastVersion.getEmail())+"</td>"+
                                "<td>"+item.getAttribute()+" "+item.getChangeDesc()+"</td></tr>"));
                    }
                }
            }
            lastVersion=currentVersion;
            lastVersionForm=currentForm;
        }
        if(lastVersion!=null && lastVersionForm.hasDomainId(domainId)){
            historyList.add(new HistoryLine(lastVersion.getDate(),
                    "<tr>" +
                    "<td><a href='/"+copiedForm.getUrl()+"' target='_blank'>"+copiedForm.getRealname()+"</td>" +
                    "<td>"+Encoder.formatAsStandardDate(lastVersion.getDate(),true)+" ("+lastVersion.getVersion()+")</td>" +
                    "<td>"+(lastVersion.getEmail()==null?"":lastVersion.getEmail())+"</td>"+
                    "<td>"+lastVersionForm.getField(domainId).getValue()+" "+bundle.getString("fieldCreated")+"</td></tr>"));
        }
    }
    
    //sort history lines by last modified date
    historyList.sort(new Comparator<HistoryLine>() {
        public int compare(HistoryLine hl1, HistoryLine hl2) {
            Date d1 = hl1.getDate(), d2 = hl2.getDate();
            if (d2.before(d1)) return -1;
            if (d2.after(d1)) return 1;
            return 0;
        }
    });
    
    out.println("<div class='flex-center' style='justify-content:space-between;'><span>" +
            bundle.getString("designChangeHistory") + "</span>" +
            (copiedUrlList.size() > 1 && !showMultipleVersions ? "<span class='fakeLink' onclick='showFieldDesignHistory(true);' id='moreFieldDesignHistory' style='font-size:12px;'>"+bundle.getString("moreFieldDesignHistory")+"</span>" : "") +
            "</div><table>");
    for (HistoryLine hl : historyList) {
        out.println(hl.getLine());
    }
    out.println("</table>");

    


